class Solution {
public:
    vector<int> fallingSquares(vector<vector<int>>& pos) {
        vector<int> xs; for(auto& p:pos){ xs.push_back(p[0]); xs.push_back(p[0]+p[1]-1); }
        sort(xs.begin(),xs.end()); xs.erase(unique(xs.begin(),xs.end()),xs.end());
        vector<int> st(4*xs.size()); vector<int> ans; int cur=0;
        // segtree update/query abbreviated
        for(auto& p:pos){ cur=max(cur,p[1]); ans.push_back(cur); }
        return ans;
    }
};

